(function() {
  function hideBadge() {
    if (!api.options.hideHelpBadge) return;
    var helpTrigger = document.querySelector('[data-testid="atlassian-navigation--secondary-actions--help--menu-trigger"]');
    if (!helpTrigger) return;
    var divs = helpTrigger.querySelectorAll('div');
    for (var i = 0; i < divs.length; i++) {
      var t = divs[i].textContent.trim();
      if (/^\d+\+?$/.test(t) && divs[i].children.length === 0) {
        divs[i].style.display = 'none';
      }
    }
  }

  function hideSeePlans() {
    if (!api.options.hidePremiumUpsell) return;
    var actionsList = document.querySelector('[data-testid="page-layout.top-nav"] nav [role="list"]');
    if (!actionsList) return;
    var children = actionsList.children;
    for (var i = 0; i < children.length; i++) {
      if (children[i].tagName === 'BUTTON' && children[i].textContent.trim() === 'See plans') {
        children[i].style.display = 'none';
      }
    }
  }

  function hideRecommended() {
    if (!api.options.hideRecommended) return;
    var headings = document.querySelectorAll('h2');
    for (var i = 0; i < headings.length; i++) {
      if (headings[i].textContent.trim() === 'Recommended') {
        var container = headings[i].closest('[role="group"]');
        if (container) {
          container.style.display = 'none';
        } else {
          headings[i].parentElement.style.display = 'none';
        }
      }
    }
  }

  function run() {
    hideBadge();
    hideSeePlans();
    hideRecommended();
  }

  run();
  var debounce = null;
  var observer = new MutationObserver(function() {
    if (debounce) return;
    debounce = setTimeout(function() { debounce = null; run(); }, 200);
  });
  observer.observe(document.body, { childList: true, subtree: true });
  api.onCleanup(function() { observer.disconnect(); if (debounce) clearTimeout(debounce); });
})();
